import{bQ as s,aL as i,u as a,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"CNI 与 Pod 网络","description":"","frontmatter":{},"headers":[],"relativePath":"10.Kubernetes/24-CNI与Pod网络.md","filePath":"10.Kubernetes/24-CNI与Pod网络.md","lastUpdated":null}'),d={name:"10.Kubernetes/24-CNI与Pod网络.md"};function h(n,t,l,p,r,k){return i(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="cni-与-pod-网络" tabindex="-1">CNI 与 Pod 网络 <a class="header-anchor" href="#cni-与-pod-网络" aria-label="Permalink to &quot;CNI 与 Pod 网络&quot;">​</a></h1><p>Kubernetes 只定义网络模型的要求——每个 Pod 有独立 IP、Pod 之间可以互通、Service 提供稳定入口。但 IP 从哪分、跨节点怎么转发、策略怎么拦截、隧道怎么封装——全部交给 CNI 插件。</p><p>网络问题的排查容易乱，因为它同时涉及 Linux 网络、K8s 资源对象和具体 CNI 实现。排查时把链路拆开，按顺序逐项验证，不要混在一起。</p><h2 id="k8s-网络模型的基本要求" tabindex="-1">K8s 网络模型的基本要求 <a class="header-anchor" href="#k8s-网络模型的基本要求" aria-label="Permalink to &quot;K8s 网络模型的基本要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要求</th><th>说明</th></tr></thead><tbody><tr><td>每个 Pod 有独立 IP</td><td>Pod 内容器共享同一个 network namespace</td></tr><tr><td>Pod 之间可互通</td><td>同节点和跨节点 Pod 都能直接访问 Pod IP</td></tr><tr><td>Node 能访问 Pod</td><td>节点能访问本机和跨节点 Pod</td></tr><tr><td>Service 提供稳定入口</td><td>Pod IP 变化后，Service 名称和 ClusterIP 不变</td></tr></tbody></table><p>同一 Pod 内容器共享网络命名空间，<code>localhost</code> 互访。不同 Pod 即使在同一台节点上，也不在同一网络命名空间——访问必须走 Pod IP 或 Service。</p><p>Pod IP 是集群内地址。外部访问不走 Pod IP，而是走 LoadBalancer、Gateway、Ingress、NodePort 或云负载均衡。</p><h2 id="pod-到-pod-的链路" tabindex="-1">Pod 到 Pod 的链路 <a class="header-anchor" href="#pod-到-pod-的链路" aria-label="Permalink to &quot;Pod 到 Pod 的链路&quot;">​</a></h2><p>同节点两个 Pod 通信：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20podA%5B%22Pod%20A%3Cbr%2F%3Eeth0%22%5D%20--%3E%20vethA%5B%22veth%20pair%22%5D%0A%20%20%20%20vethA%20--%3E%20bridge%5B%22%E8%8A%82%E7%82%B9%E7%BD%91%E6%A1%A5%20%2F%20CNI%20%E8%AE%BE%E5%A4%87%22%5D%0A%20%20%20%20bridge%20--%3E%20vethB%5B%22veth%20pair%22%5D%0A%20%20%20%20vethB%20--%3E%20podB%5B%22Pod%20B%3Cbr%2F%3Eeth0%22%5D%0A"></div><p>跨节点多了一段节点间转发：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20podA%5B%22%E8%8A%82%E7%82%B9%2001%20%2F%20Pod%20A%22%5D%20--%3E%20vethA%5B%22veth%22%5D%0A%20%20%20%20vethA%20--%3E%20nodeA%5B%22%E8%8A%82%E7%82%B9%2001%20%E8%B7%AF%E7%94%B1%E6%88%96%E9%9A%A7%E9%81%93%22%5D%0A%20%20%20%20nodeA%20--%3E%20underlay%5B%22%E5%AE%BF%E4%B8%BB%E6%9C%BA%E7%BD%91%E7%BB%9C%22%5D%0A%20%20%20%20underlay%20--%3E%20nodeB%5B%22%E8%8A%82%E7%82%B9%2002%20%E8%B7%AF%E7%94%B1%E6%88%96%E9%9A%A7%E9%81%93%22%5D%0A%20%20%20%20nodeB%20--%3E%20vethB%5B%22veth%22%5D%0A%20%20%20%20vethB%20--%3E%20podB%5B%22%E8%8A%82%E7%82%B9%2002%20%2F%20Pod%20B%22%5D%0A"></div><p>&quot;路由或隧道&quot;由 CNI 决定——Flannel 用 VXLAN，Calico 可选 IPIP/VXLAN/BGP，Cilium 用 eBPF 数据面。排查时先确认跨节点 Pod IP 是否互通，不通再看 CNI 的具体转发方式。</p><p>验证链路：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在两个不同节点上各跑一个临时 Pod</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 记下 Pod IP 和所在节点</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从一个 Pod ping 另一个 Pod 的 IP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ping</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-b-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>跨节点 ping 不通时，先看节点路由有没有 Pod 网段。比如 node-a 上没有到 node-b Pod CIDR 的路由，基本能定位在 CNI 路由下发；路由存在但 <code>tcpdump</code> 看不到对端返回包，再看防火墙、VXLAN/IPIP 隧道或 BGP 状态。</p><h2 id="三种网络对象要分清" tabindex="-1">三种网络对象要分清 <a class="header-anchor" href="#三种网络对象要分清" aria-label="Permalink to &quot;三种网络对象要分清&quot;">​</a></h2><table tabindex="0"><thead><tr><th>验证对象</th><th>做什么</th><th>不通时看什么</th></tr></thead><tbody><tr><td>Pod IP</td><td>Pod 之间直连</td><td>CNI、路由、隧道、防火墙</td></tr><tr><td>Service ClusterIP</td><td>Service 到 Pod</td><td>kube-proxy、EndpointSlice、Service selector</td></tr><tr><td>DNS</td><td>Service 名到 ClusterIP</td><td>CoreDNS、NetworkPolicy、Pod DNS 配置</td></tr></tbody></table><p>Pod IP 通但 Service 不通——问题在 kube-proxy 和 Service 层。Service 通但域名不通——问题在 CoreDNS。</p><h2 id="常见-cni" tabindex="-1">常见 CNI <a class="header-anchor" href="#常见-cni" aria-label="Permalink to &quot;常见 CNI&quot;">​</a></h2><table tabindex="0"><thead><tr><th>插件</th><th>实现方式</th><th>适合场景</th></tr></thead><tbody><tr><td>Flannel</td><td>VXLAN 隧道</td><td>实验、小集群，简单够用</td></tr><tr><td>Calico</td><td>BGP / IPIP / VXLAN，NetworkPolicy 成熟</td><td>传统机房、通用生产集群</td></tr><tr><td>Cilium</td><td>eBPF 数据面，Hubble 可观测性，策略和 Gateway 能力强</td><td>新集群，需要强网络观测和安全能力</td></tr></tbody></table><p>Calico 在传统机房常见——IPIP、VXLAN、BGP 都支持得成熟，不依赖特定网络设备。Cilium 把数据面做到 eBPF 里，用 Hubble 直接看流量路径和丢包点——排查方式从看 iptables 规则转向流量可视化。</p><h2 id="pod-cidr-和-service-cidr" tabindex="-1">Pod CIDR 和 Service CIDR <a class="header-anchor" href="#pod-cidr-和-service-cidr" aria-label="Permalink to &quot;Pod CIDR 和 Service CIDR&quot;">​</a></h2><p>K8s 集群有两个网段必须在初始化时规划：</p><table tabindex="0"><thead><tr><th>网段</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td>Pod CIDR</td><td>给 Pod 分配 IP</td><td><code>10.244.0.0/16</code></td></tr><tr><td>Service CIDR</td><td>给 ClusterIP 分配 IP</td><td><code>10.96.0.0/12</code></td></tr></tbody></table><p>这两个网段需要避开公司内网、VPN 网段、Docker 默认网段、云 VPC 网段。路由冲突的典型表现不是全部断开，而是部分地址路由异常——访问公司某个网段走了 Pod 路由，或者 VPN 连上后某些 Service 解析出来 IP 能通但端口不通。这类问题容易排查很久，因为现象不是&quot;全断&quot;而是&quot;有时不通&quot;。</p><h2 id="calico-三种模式" tabindex="-1">Calico 三种模式 <a class="header-anchor" href="#calico-三种模式" aria-label="Permalink to &quot;Calico 三种模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>原理</th><th>注意事项</th></tr></thead><tbody><tr><td>IPIP</td><td>Pod 流量封装进 IPIP 包跨节点传输</td><td>底层网络不感知 Pod 路由，注意 MTU</td></tr><tr><td>VXLAN</td><td>VXLAN 隧道封装跨节点流量</td><td>云和跨三层网络常见，注意 UDP 4789 端口</td></tr><tr><td>BGP</td><td>节点间或和交换机通过 BGP 分发 Pod 路由</td><td>性能好，但依赖网络设备配合</td></tr></tbody></table><p>隧道模式（IPIP、VXLAN）的好处：底层网络不用知道 Pod 网段——宿主机之间先包一层再发。代价是多一层封装，MTU 配不好时大包异常。BGP 模式把 Pod 网段直接通告给网络设备，延迟更低，但需要交换机或路由器支持 BGP 对等。</p><h2 id="mtu、防火墙、conntrack" tabindex="-1">MTU、防火墙、conntrack <a class="header-anchor" href="#mtu、防火墙、conntrack" aria-label="Permalink to &quot;MTU、防火墙、conntrack&quot;">​</a></h2><p>CNI 封装会增加额外头部。原本 1500 的包，VXLAN 封装后可能超过底层 MTU——表现是小包通、大包不通，或者 TCP 握手成功但传大响应时卡住。</p><p>防火墙除了 TCP 端口，还要放行 CNI 协议：</p><table tabindex="0"><thead><tr><th>协议</th><th>端口/类型</th></tr></thead><tbody><tr><td>VXLAN</td><td>UDP 4789</td></tr><tr><td>IPIP</td><td>IP 协议号 4</td></tr><tr><td>BGP</td><td>TCP 179</td></tr><tr><td>kube-apiserver</td><td>TCP 6443</td></tr><tr><td>NodePort</td><td>TCP/UDP 30000-32767</td></tr></tbody></table><p>conntrack 表满时 Service 访问出现间歇失败，和 Deployment、Service YAML 无关：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.netfilter.nf_conntrack_max</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">conntrack</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conntrack</span></span></code></pre></div><p><code>nf_conntrack: table full</code> 出现时，看节点上的短连接数量、<code>nf_conntrack_max</code> 大小和超时参数。这个现象在 Service 多的集群和高并发短连接场景容易出现。</p><h2 id="跨节点不通排查" tabindex="-1">跨节点不通排查 <a class="header-anchor" href="#跨节点不通排查" aria-label="Permalink to &quot;跨节点不通排查&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net-test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image=busybox:1.36</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --restart=Never</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sh</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Pod 内</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">other-pod-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">service-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nslookup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">service-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.svc.cluster.local</span></span></code></pre></div><p>节点上看路由和规则：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables-save</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;CALI|CILIUM|FLANNEL|KUBE&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -50</span></span></code></pre></div><table tabindex="0"><thead><tr><th>现象</th><th>方向</th></tr></thead><tbody><tr><td>新 Pod 没 IP</td><td>CNI 插件异常、IP 池耗尽、kubelet 调 CNI 失败</td></tr><tr><td>同节点通、跨节点不通</td><td>隧道、防火墙、路由、BGP、MTU</td></tr><tr><td>Pod IP 通、Service 不通</td><td>kube-proxy、EndpointSlice、selector、端口</td></tr><tr><td>Service 通、域名不通</td><td>CoreDNS、搜索域、NetworkPolicy</td></tr><tr><td>小包通、大包卡</td><td>MTU、封装、中间设备</td></tr><tr><td>间歇性失败</td><td>conntrack、节点压力、CNI Agent 重启</td></tr></tbody></table><p>Cilium 集群用 Hubble 直接看流量路径和丢包点；Calico 集群更常看 IPPool、BGP 状态、felix 日志和节点路由。CNI 不同，排查入口也会变——只靠 <code>kubectl describe pod</code> 看不到底层网络问题。</p>`,42)])])}const F=s(d,[["render",h]]);export{c as __pageData,F as default};
